import os
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from PIL import Image
import io
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# AWS S3 Configuration
S3_BUCKET_NAME = os.environ.get('S3_BUCKET_NAME', 'your-screenshot-bucket-name')
S3_REGION = os.environ.get('AWS_REGION', 'us-east-1')
s3_client = boto3.client('s3', region_name=S3_REGION)

# Chrome Driver Path (assuming it's in the same directory or accessible via PATH)
# On EC2, you might install chrome and chromedriver via package manager
# e.g., sudo yum install chromium chromedriver -y (for Amazon Linux 2)
CHROME_DRIVER_PATH = os.environ.get('CHROME_DRIVER_PATH', '/usr/bin/chromedriver')
HEADLESS_CHROME_BINARY = os.environ.get('HEADLESS_CHROME_BINARY', '/usr/bin/google-chrome') # or chromium-browser

# Thumbnail Configuration
THUMBNAIL_WIDTH = 320
THUMBNAIL_HEIGHT = 180
SCREENSHOT_FULL_WIDTH = 1280
SCREENSHOT_FULL_HEIGHT = 720 # This will be the viewport height, page might be taller

def setup_chrome_options():
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument(f'--window-size={SCREENSHOT_FULL_WIDTH},{SCREENSHOT_FULL_HEIGHT}')
    chrome_options.add_argument('--hide-scrollbars')
    chrome_options.add_argument('--enable-automation')
    chrome_options.add_argument('--disable-gpu') # Important for some environments
    chrome_options.binary_location = HEADLESS_CHROME_BINARY
    return chrome_options

def take_screenshot_and_thumbnail(url):
    driver = None
    try:
        logging.info(f"Attempting to screenshot URL: {url}")
        chrome_options = setup_chrome_options()
        driver = webdriver.Chrome(CHROME_DRIVER_PATH, options=chrome_options)

        driver.get(url)
        driver.set_window_size(SCREENSHOT_FULL_WIDTH, SCREENSHOT_FULL_HEIGHT) # Ensure consistent viewport

        # Give some time for page to load and render, especially for JS-heavy sites
        driver.implicitly_wait(5)
        # You might need to adjust this, or use explicit waits for specific elements
        # time.sleep(2)

        # Get the full page screenshot as bytes
        full_screenshot_png = driver.get_screenshot_as_png()
        logging.info("Full screenshot taken.")

        # Create a PIL Image from the screenshot bytes
        img = Image.open(io.BytesIO(full_screenshot_png))

        # Crop if needed to ensure aspect ratio or specific area before resizing
        # For a simple thumbnail, we'll just resize. If you want a specific crop,
        # you'd calculate a box (left, upper, right, lower)
        # For instance, to crop to a 16:9 ratio before resize:
        # original_width, original_height = img.size
        # target_aspect_ratio = THUMBNAIL_WIDTH / THUMBNAIL_HEIGHT
        # if original_width / original_height > target_aspect_ratio:
        #     # Image is wider than target, crop width
        #     new_width = int(original_height * target_aspect_ratio)
        #     left = (original_width - new_width) // 2
        #     img = img.crop((left, 0, left + new_width, original_height))
        # else:
        #     # Image is taller than target, crop height
        #     new_height = int(original_width / target_aspect_ratio)
        #     top = (original_height - new_height) // 2
        #     img = img.crop((0, top, original_width, top + new_height))

        # Resize to thumbnail dimensions
        img.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.LANCZOS)
        logging.info(f"Thumbnail resized to {THUMBNAIL_WIDTH}x{THUMBNAIL_HEIGHT}.")

        # Save thumbnail to a bytes buffer
        thumbnail_byte_arr = io.BytesIO()
        img.save(thumbnail_byte_arr, format='PNG')
        thumbnail_byte_arr.seek(0)

        return thumbnail_byte_arr.getvalue()

    except Exception as e:
        logging.error(f"Error taking screenshot for {url}: {e}", exc_info=True)
        return None
    finally:
        if driver:
            driver.quit()

def upload_to_s3(image_bytes, key, content_type='image/png'):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET_NAME,
            Key=key,
            Body=image_bytes,
            ContentType=content_type,
            ACL='public-read' # Adjust ACL based on your requirements
        )
        s3_url = f"https://{S3_BUCKET_NAME}.s3.{S3_REGION}.amazonaws.com/{key}"
        logging.info(f"Successfully uploaded {key} to S3: {s3_url}")
        return s3_url
    except Exception as e:
        logging.error(f"Error uploading {key} to S3: {e}", exc_info=True)
        return None

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    data = request.get_json()
    if not data or 'url' not in data:
        return jsonify({"error": "URL not provided. Please send a JSON payload with 'url'."}), 400

    target_url = data['url']
    if not (target_url.startswith('http://') or target_url.startswith('https://')):
        target_url = 'http://' + target_url # Prepend http:// if missing

    try:
        # Generate a unique key for S3
        import hashlib
        import datetime
        url_hash = hashlib.md5(target_url.encode('utf-8')).hexdigest()
        timestamp = datetime.datetime.now().strftime('%Y%m%d%H%M%S')
        s3_key = f"screenshots/{url_hash}-{timestamp}.png"

        thumbnail_bytes = take_screenshot_and_thumbnail(target_url)

        if thumbnail_bytes:
            s3_url = upload_to_s3(thumbnail_bytes, s3_key)
            if s3_url:
                return jsonify({
                    "message": "Screenshot generated and uploaded successfully",
                    "url": target_url,
                    "thumbnail_url": s3_url
                }), 200
            else:
                return jsonify({"error": "Failed to upload thumbnail to S3."}), 500
        else:
            return jsonify({"error": "Failed to generate thumbnail."}), 500

    except Exception as e:
        logging.error(f"Unhandled error in screenshot_service for URL {target_url}: {e}", exc_info=True)
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

@app.route('/')
def health_check():
    return "Screenshot service is running!"

