    # sudo yum install -y chromium chromium-chromedriver
    # export CHROME_DRIVER_PATH=/usr/bin/chromedriver
    # export HEADLESS_CHROME_BINARY=/usr/bin/chromium-browser

    app.run(host='0.0.0.0', port=5000)